1472→    /**
1473→     * Plays sounds (or TTS, if configured) for currently shown side of card.
1474→     *
1475→     * @param doAudioReplay indicates an anki desktop-like replay call is desired, whose behavior is identical to
1476→     * pressing the keyboard shortcut R on the desktop
1477→     */
1478→    @NeedsTest("audio is not played if opExecuted occurs when viewer is in the background")
1479→    protected open fun playSounds(doAudioReplay: Boolean) {
1480→        // this can occur due to OpChanges when the viewer is on another screen
1481→        if (!this.lifecycle.currentState.isAtLeast(RESUMED)) {
1482→            Timber.w("sounds are not played as the activity is inactive")
1483→            return
1484→        }
1485→        if (!cardMediaPlayer.config.autoplay && !doAudioReplay) return
1486→        // Use TTS if TTS preference enabled and no other sound source
1487→        val useTTS = tts.enabled && !cardMediaPlayer.hasSounds(displayAnswer)
1488→        // We need to play the sounds from the proper side of the card
1489→        if (!useTTS) {
1490→            launchCatchingTask {
1491→                val side = if (displayAnswer) SingleCardSide.BACK else SingleCardSide.FRONT
1492→                when (doAudioReplay) {
1493→                    true -> cardMediaPlayer.replayAllSounds(side)
1494→                    false -> cardMediaPlayer.playAllSounds(side)
1495→                }
1496→            }
1497→            return
1498→        }
1499→
1500→        val replayQuestion = cardMediaPlayer.config.replayQuestion
1501→        // Text to speech is in effect here
1502→        // If the question is displayed or if the question should be replayed, read the question
1503→        if (ttsInitialized) {
1504→            if (!displayAnswer || doAudioReplay && replayQuestion) {
1505→                readCardTts(SingleCardSide.FRONT)
1506→            }
1507→            if (displayAnswer) {
1508→                readCardTts(SingleCardSide.BACK)
1509→            }
1510→        } else {
1511→            replayOnTtsInit = true
1512→        }
1513→    }
