    protected fun isAutoAdvanceEnabled(): Boolean {
        return sharedPrefs().getBoolean(TIMEOUT_ANSWER_PREF_KEY, false)
    }

    protected fun setAutoAdvanceEnabled(enabled: Boolean): Boolean {
        val preferences = sharedPrefs()
        val current = preferences.getBoolean(TIMEOUT_ANSWER_PREF_KEY, false)
        if (current == enabled) {
            return false
        }
        preferences.edit { putBoolean(TIMEOUT_ANSWER_PREF_KEY, enabled) }
        rebuildAutomaticAnswer(preferences)
        if (enabled) {
            rescheduleAutomaticAnswerForCurrentSide()
        }
        return true
    }

    private fun rebuildAutomaticAnswer(preferences: SharedPreferences) {
        automaticAnswer.disable()
        automaticAnswer = if (colIsOpenUnsafe()) {
            AutomaticAnswer.createInstance(this, preferences, getColUnsafe)
        } else {
            AutomaticAnswer.defaultInstance(this)
        }
    }

    protected fun rescheduleAutomaticAnswerForCurrentSide() {
        if (!automaticAnswer.isEnabled()) {
            return
        }
        if (currentCard == null) {
            return
        }
        if (displayAnswer) {
            automaticAnswer.onDisplayAnswer()
        } else {
            automaticAnswer.onDisplayQuestion()
        }
        launchCatchingTask {
            if (!automaticAnswerShouldWaitForAudio()) {
                if (displayAnswer) {
                    automaticAnswer.scheduleAutomaticDisplayQuestion()
                } else {
                    automaticAnswer.scheduleAutomaticDisplayAnswer()
                }
            }
        }
    }

    private fun setInterface() {
